/* ── TEAM STATS TAB ──────────────────────────────────────────────────────── */
/* ─────────────────────────────────────────────────────────────────────────
   SPLITS TAB — all hitter cards (5-across desktop / 1-across phone),
   a red divider, then all pitcher cards in the same grid.
   ───────────────────────────────────────────────────────────────────────── */
function SplitsCard({T, player, kind, onClick, splitsKey = "risp"}) {
  const tier = kind === "hitter" ? hitterRoleTier(player) : pitcherRoleTier(player);
  const photo = HEADSHOTS[player.name];
  // Stat lines per card type
  const stats = kind === "hitter"
    ? (() => {
        const rsp = player.splits?.[splitsKey] || {};
        return [
          { label:"AVG", value:rsp.avg },
          { label:"OBP", value:rsp.obp },
          { label:"SLG", value:rsp.slg },
          { label:"OPS", value:rsp.ops },
          { label:"wOBA",value:rsp.woba },
          { label:"wRC+",value:rsp.wrc },
          { label:"BB%", value:rsp.bbpct },
          { label:"K%",  value:rsp.kpct },
        ];
      })()
: (() => {
        const sp = player.splits?.[splitsKey] || {};
        return [
          { label:"IP",    value:sp.ip },
          { label:"ERA",   value:sp.era },
          { label:"FIP",   value:sp.fip },
          { label:"xFIP",  value:sp.xfip },
          { label:"WHIP",  value:(() => {
              const w = parseFloat(sp.whip);
              return isNaN(w) ? sp.whip : w.toFixed(2);
            })() },
          { label:"AVG",   value:sp.avg },
          { label:"wOBA",  value:sp.woba },
          { label:"K-BB%", value:(() => {
              const k = parseFloat(sp.kpct), b = parseFloat(sp.bbpct);
              return (isNaN(k) || isNaN(b)) ? "—" : `${(k - b).toFixed(1)}%`;
            })() },
        ];
      })();
  return (
    <button onClick={onClick} className="brv-splits-card brv-card-shine" style={{
      background: T === THEME.dark
        ? "linear-gradient(160deg, rgba(19,39,79,0.55) 0%, rgba(10,21,48,0.85) 100%)"
        : "linear-gradient(160deg, #ffffff 0%, #eef2f8 100%)",
      border:`1px solid ${tier.border}55`,
      borderTop:`3px solid ${tier.border}`,
      borderRadius:12, padding:"14px 12px 12px",
      cursor:"pointer", textAlign:"left", fontFamily:"inherit",
      display:"flex", flexDirection:"column", gap:10,
      boxShadow:"0 2px 10px rgba(0,0,0,0.2)",
    }}>
      {/* Header: avatar + name + badge */}
      <div style={{display:"flex", alignItems:"center", gap:10}}>
        <div style={{
          width:46, height:46, borderRadius:"50%",
          background: photo
            ? `url(${photo}) center/cover, linear-gradient(135deg, ${tier.bg1} 0%, ${tier.bg2} 100%)`
            : `linear-gradient(135deg, ${tier.bg1} 0%, ${tier.bg2} 100%)`,
          border:`2px solid ${tier.border}`,
          display:"flex", alignItems:"center", justifyContent:"center",
          fontSize:14, fontWeight:800, color:"#fff",
          boxShadow:`0 0 10px ${tier.glow}`, flexShrink:0, overflow:"hidden",
        }}>{photo ? "" : initials(player.name)}</div>
        <div style={{flex:1, minWidth:0}}>
          <div style={{fontSize:13, fontWeight:700, color:T.text, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis"}}>{player.name}</div>
          <div style={{display:"flex", alignItems:"center", gap:6, marginTop:3}}>
            <span style={{fontSize:9, color:T.textMuted, fontWeight:700, letterSpacing:"0.08em"}}>{player.pos || player.role || "P"}</span>
            <span style={{
              fontSize:8.5, fontWeight:800, letterSpacing:"0.1em",
              color: T === THEME.dark ? tier.color : "#fff",
              border:`1px solid ${T === THEME.dark ? tier.border : BRAND.red}`,
              borderRadius:4,
              padding:"1px 5px",
              background: T === THEME.dark ? "rgba(0,0,0,0.15)" : BRAND.red,
            }}>{tier.label}</span>
          </div>
        </div>
      </div>
      {/* Stat grid — 4 columns */}
      <div style={{display:"grid", gridTemplateColumns:"repeat(4, 1fr)", gap:"6px 4px"}}>
        {stats.map(st => (
          <div key={st.label} style={{textAlign:"center"}}>
            <div style={{fontSize:8, color:T.textMuted, fontWeight:700, letterSpacing:"0.06em", marginBottom:1}}>{st.label}</div>
            <div style={{fontSize:11.5, fontWeight:700, color: (st.label === "wRC+" || st.label === "K-BB%") ? "#22c55e" : T.text, fontFamily:"'JetBrains Mono',monospace"}}>{st.value ?? "—"}</div>
          </div>
        ))}
      </div>
    </button>
  );
}

function ExpandedProfile({T, mode, kind, player, scale, onClose}) {
  const innerRef = useRef(null);
  const [h, setH] = useState(null);
  useEffect(() => {
    if (!innerRef.current) return;
    const measure = () => {
      if (innerRef.current) setH(innerRef.current.offsetHeight * scale);
    };
    measure();
    // Re-measure when the profile's inner tab changes height
    const ro = typeof ResizeObserver !== "undefined" ? new ResizeObserver(measure) : null;
    if (ro && innerRef.current) ro.observe(innerRef.current);
    return () => { if (ro) ro.disconnect(); };
  }, [scale, kind, player]);
  return (
    <div className="brv-splits-expand" style={{ height: h ? `${h}px` : undefined }}>
      <div ref={innerRef} style={{ transform:`scale(${scale})`, transformOrigin:"top left", width:`${100/scale}%` }}>
        <FullProfile T={T} mode={mode} player={{kind, data:player}} onClose={onClose}/>
      </div>
    </div>
  );
}

function SplitsTab({T, mode}) {
  const splitsHitters = hitters.filter(h => !HIDDEN_PLAYERS.has(h.name));
  const splitsPitchers = [...starters, ...bullpen].filter(p => !HIDDEN_PLAYERS.has(p.name));
  // Local toggle: which side of the splits we're viewing (hitters or pitchers)
  const [splitsView, setSplitsView] = useState("hitters");
  // Which card is expanded in place. Keyed by section + name so the same
  // player can be open in one grid without expanding in the other.
  const [expanded, setExpanded] = useState(null);
  const keyFor = (section, name) => `${section}:${name}`;
  const toggle = (section, name) => setExpanded(prev => prev === keyFor(section, name) ? null : keyFor(section, name));
  // Phones (single-column grid) get a gentler shrink than wide screens.
  const isNarrow = typeof window !== "undefined" && window.innerWidth <= 560;
  const scale = isNarrow ? 0.8 : 0.6;
  const renderGrid = (list, section, splitsKey, kind) => (
    <div className="brv-splits-grid">
      {list.map(pl => {
        const isOpen = expanded === keyFor(section, pl.name);
        return isOpen ? (
          <ExpandedProfile key={pl.name} T={T} mode={mode} kind={kind} player={pl} scale={scale} onClose={()=>setExpanded(null)}/>
        ) : (
          <SplitsCard key={pl.name} T={T} player={pl} kind={kind} splitsKey={splitsKey} onClick={()=>toggle(section, pl.name)}/>
        );
      })}
    </div>
  );

  // Section labels swap with the view
  const topLabel    = splitsView === "hitters" ? "HITTERS · with RISP"      : "PITCHERS · vs LHH";
  const bottomLabel = splitsView === "hitters" ? "HITTERS · High Leverage"  : "PITCHERS · vs RHH";
  const topKey      = splitsView === "hitters" ? "risp"         : "vsL";
  const bottomKey   = splitsView === "hitters" ? "highLeverage" : "vsR";
  const topSection    = splitsView === "hitters" ? "risp" : "vsL";
  const bottomSection = splitsView === "hitters" ? "hl"   : "vsR";
  const list = splitsView === "hitters" ? splitsHitters : splitsPitchers;
  const kind = splitsView === "hitters" ? "hitter" : "pitcher";

  // Reset expanded card when switching views so nothing carries over
  const handleViewChange = (v) => {
    setSplitsView(v);
    setExpanded(null);
  };

  return (
    <>
      <TabTitle T={T} eyebrow="EVERY PLAYER · CARD VIEW" title="SPLITS"/>
      <div style={{display:"flex", gap:6, marginBottom:10}}>
        {["hitters","pitchers"].map(v => (
          <button key={v} onClick={()=>handleViewChange(v)} style={{
            background: splitsView === v ? "linear-gradient(135deg, rgba(206,17,65,0.20), rgba(196,163,90,0.12))" : "transparent",
            border:`1px solid ${splitsView === v ? BRAND.gold : T.borderFaint}`,
            borderRadius:6, padding:"5px 12px", fontSize:10.5, fontWeight:700,
            color: splitsView === v ? BRAND.goldBright : T.textMid,
            cursor:"pointer", letterSpacing:"0.10em", textTransform:"uppercase",
          }}>{v}</button>
        ))}
      </div>
      <div style={{fontSize:11, color:T.textMuted, marginBottom:14, lineHeight:1.4}}>
        {splitsView === "hitters"
          ? "Hitters with RISP up top, high-leverage splits in the middle, with 2 outs down below · tap any card to expand it in place"
          : "Pitchers vs LHH up top, vs RHH below the line · tap any card to expand it in place"}
      </div>
      {/* TOP SECTION */}
      <div style={{
        fontSize:11, fontWeight:800, letterSpacing:"0.12em", color:BRAND.goldBright,
        fontFamily:"'Cinzel',serif", marginBottom:10,
      }}>{topLabel}</div>
      {renderGrid(list, topSection, topKey, kind)}
      {/* RED DIVIDER — matches the STARTER badge red/black */}
      <div style={{
        height:4, borderRadius:3, margin:"26px 0 22px",
        background:`linear-gradient(90deg, ${BRAND.red} 0%, #8a0a28 100%)`,
        boxShadow:`0 0 12px rgba(206,17,65,0.55)`,
        border:`1px solid ${BRAND.goldBright}55`,
      }}/>
      {/* BOTTOM SECTION */}
      <div style={{
        fontSize:11, fontWeight:800, letterSpacing:"0.12em", color:BRAND.goldBright,
        fontFamily:"'Cinzel',serif", marginBottom:10,
      }}>{bottomLabel}</div>
      {renderGrid(list, bottomSection, bottomKey, kind)}
      {/* THIRD SECTION — HITTERS · With 2 Outs (hitters view only) */}
      {splitsView === "hitters" && (
        <>
          <div style={{
            height:4, borderRadius:3, margin:"26px 0 22px",
            background:`linear-gradient(90deg, ${BRAND.red} 0%, #8a0a28 100%)`,
            boxShadow:`0 0 12px rgba(206,17,65,0.55)`,
            border:`1px solid ${BRAND.goldBright}55`,
          }}/>
          <div style={{
            fontSize:11, fontWeight:800, letterSpacing:"0.12em", color:BRAND.goldBright,
            fontFamily:"'Cinzel',serif", marginBottom:10,
          }}>HITTERS · With 2 Outs</div>
          {renderGrid(splitsHitters, "twoOuts", "twoOuts", "hitter")}
        </>
      )}
    </>
  );
}

// ============================================================================
// TEAM STATS — module-level helpers
// Defined OUTSIDE TeamStatsTab so rolldown's JSX parser doesn't trip on
// nested arrow components. All four functions below are plain hoisted
// function declarations.
// ============================================================================

function tsCellHeat(value, ref) {
  if (!ref) return {};
  const num = typeof value === "number" ? value : parseFloat(String(value).replace("%",""));
  if (isNaN(num)) return {};
  let delta = (num - ref.mean) / ref.spread;
  if (ref.invert) delta = -delta;
  const mag = Math.min(Math.abs(delta), 2);
  if (mag < 0.30) return {};
  const intensity = mag / 2;
  const alpha = (0.08 + intensity * 0.26).toFixed(3);
  if (delta > 0) {
    return { background: "rgba(206,17,65," + alpha + ")", color: "#8a1a3c" };
  }
  return { background: "rgba(70,110,180," + alpha + ")", color: "#2d4f88" };
}

function TSMiniTable(props) {
  const rows = props.rows;
  const sT = props.sT;
  const gap = typeof props.bottomGap === "number" ? props.bottomGap : 12;
  const labelWidth = "22%";
  const dataWidth = (78 / rows.length).toFixed(2) + "%";
  const redBorder = "1.5px solid " + BRAND.red;
  const rowBorder = "1px solid " + sT.borderFaint;

  const labelHdrStyle = {
    width: labelWidth,
    textAlign: "left", padding: "3px 4px", fontSize: 8.5, fontWeight: 700,
    letterSpacing: "0.06em", color: sT.textMuted, textTransform: "uppercase",
    borderBottom: redBorder,
  };
  const dataHdrStyle = {
    width: dataWidth,
    textAlign: "center", padding: "3px 2px", fontSize: 8.5, fontWeight: 700,
    letterSpacing: "0.04em", color: sT.textMuted, textTransform: "uppercase",
    borderBottom: redBorder,
    whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
  };
  const bravesLabelStyle = {
    textAlign: "left", padding: "5px 4px",
    fontFamily: "'Cinzel', Georgia, serif",
    fontSize: 9, fontWeight: 800, letterSpacing: "0.10em",
    color: sT.text, textTransform: "uppercase", borderBottom: rowBorder,
  };
  const bravesValueBase = {
    textAlign: "center", padding: "5px 2px", fontSize: 11.5, fontWeight: 800,
    color: sT.text, borderBottom: rowBorder, whiteSpace: "nowrap",
  };
  const lgLabelStyle = {
    textAlign: "left", padding: "4px 4px",
    fontFamily: "'Cinzel', Georgia, serif",
    fontSize: 8.5, fontWeight: 700, letterSpacing: "0.10em",
    color: sT.textMuted, textTransform: "uppercase",
  };
  const lgValueStyle = {
    textAlign: "center", padding: "4px 2px", fontSize: 10, fontWeight: 600,
    color: sT.textMuted, whiteSpace: "nowrap",
  };
  const tableStyle = {
    width: "100%", borderCollapse: "collapse",
    tableLayout: "fixed", fontSize: 10,
  };
  const tbodyStyle = {
    fontFamily: "'JetBrains Mono', 'SF Mono', Consolas, monospace",
  };
  const wrapStyle = { overflowX: "auto", marginBottom: gap };

  return (
    <div style={wrapStyle}>
      <table style={tableStyle}>
        <thead>
          <tr>
            <th style={labelHdrStyle}></th>
            {rows.map(r => <th key={r.label} style={dataHdrStyle}>{r.label}</th>)}
          </tr>
        </thead>
        <tbody style={tbodyStyle}>
          <tr>
            <td style={bravesLabelStyle}>BRAVES</td>
            {rows.map(r => {
              const merged = Object.assign({}, bravesValueBase, tsCellHeat(r.value, r.heatRef));
              return <td key={r.label} style={merged}>{r.value}</td>;
            })}
          </tr>
          <tr>
            <td style={lgLabelStyle}>Lg avg</td>
            {rows.map(r => <td key={r.label} style={lgValueStyle}>{r.sub.replace(/^lg\s*/i, "")}</td>)}
          </tr>
        </tbody>
      </table>
    </div>
  );
}

function TSSectionLabel(props) {
  const sT = props.sT;
  const style = {
    fontFamily: "'Cinzel', Georgia, serif",
    fontSize: 10.5, fontWeight: 800, letterSpacing: "0.20em",
    color: sT.text, textTransform: "uppercase",
    marginBottom: 6, marginTop: 12,
    padding: "4px 10px",
    background: "rgba(0,0,0,0.05)",
    borderLeft: "3px solid " + BRAND.red,
    borderRadius: "0 3px 3px 0",
  };
  return <div style={style}>{props.children}</div>;
}

function TSSideCard(props) {
  const sT = props.sT;
  const sections = props.sections;
  const cardStyle = {
    position: "relative", background: sT.rowBase, borderRadius: 10,
    padding: "16px 12px 12px", minWidth: 0, overflow: "hidden",
  };
  const stripStyle = {
    position: "absolute", top: 0, left: 0, right: 0, height: 3,
    background: "linear-gradient(90deg, " + BRAND.red + " 0%, #8a0a28 100%)",
    borderTopLeftRadius: 9, borderTopRightRadius: 9,
    boxShadow: "0 0 10px rgba(206,17,65,0.45)",
  };
  const titleStyle = {
    fontFamily: "'Cinzel', Georgia, serif", fontSize: 12, fontWeight: 800,
    letterSpacing: "0.20em", color: sT.textMid, textTransform: "uppercase",
    marginBottom: 10,
  };

  return (
    <div style={cardStyle}>
      <div style={stripStyle}></div>
      <div style={titleStyle}>{props.title}</div>
      {sections.map((s, i) => {
        // Tight pair spacing: if next section has null label, current is first-of-pair.
        const next = sections[i + 1];
        const isPairStart = next && next.label === null;
        const gap = isPairStart ? 4 : 12;
        return (
          <div key={i}>
            {s.label ? <TSSectionLabel sT={sT}>{s.label}</TSSectionLabel> : null}
            <TSMiniTable rows={s.rows} sT={sT} bottomGap={gap} />
          </div>
        );
      })}
    </div>
  );
}

